-- Issue #69 follow-up: additive exercise catalog identity expansion and reviewed aliases.
-- Hosted status: not applied by Codex. Apply only through the normal Supabase migration flow.

on conflict (id) do update set
  display_name = excluded.display_name,
  normalized_lookup_key = excluded.normalized_lookup_key,
  equipment_tags = excluded.equipment_tags,
  movement_pattern = excluded.movement_pattern,
  qualifier_text = excluded.qualifier_text,
  metadata = excluded.metadata,
  updated_at = now()
where public.exercise_identities.owner_scope = 'system';

on conflict (normalized_lookup_key) where owner_scope = 'system' and reviewed do update set
  exercise_identity_id = excluded.exercise_identity_id,
  alias = excluded.alias,
  updated_at = now()
where public.exercise_aliases.owner_scope = 'system' and public.exercise_aliases.reviewed;
